import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"Sandboxes And Storage","description":"","frontmatter":{},"headers":[],"relativePath":"admin/sandboxes-storage.md","filePath":"admin/sandboxes-storage.md","lastUpdated":null}'),r={name:"admin/sandboxes-storage.md"};function n(o,e,l,d,h,c){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="sandboxes-and-storage" tabindex="-1">Sandboxes And Storage <a class="header-anchor" href="#sandboxes-and-storage" aria-label="Permalink to &quot;Sandboxes And Storage&quot;">​</a></h1><p>Sandbox and storage settings define where agent work happens and where run artifacts live. Treat both as part of the security boundary.</p><h2 id="sandbox-purpose" tabindex="-1">Sandbox purpose <a class="header-anchor" href="#sandbox-purpose" aria-label="Permalink to &quot;Sandbox purpose&quot;">​</a></h2><p>Agent tasks can generate code, run commands, inspect repositories, or call tools. Sandboxes isolate that work from the control plane and let policy choose the right execution boundary.</p><h2 id="providers" tabindex="-1">Providers <a class="header-anchor" href="#providers" aria-label="Permalink to &quot;Providers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Provider</th><th>Use when</th></tr></thead><tbody><tr><td>Docker</td><td>Local development, quickstart, and simple self-hosted installs.</td></tr><tr><td>OpenSandbox</td><td>Stronger isolated execution and egress control.</td></tr><tr><td>Kubernetes</td><td>Cluster-native execution, including Kata-style isolation when configured.</td></tr></tbody></table><h2 id="profiles" tabindex="-1">Profiles <a class="header-anchor" href="#profiles" aria-label="Permalink to &quot;Profiles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Profile</th><th>Typical use</th></tr></thead><tbody><tr><td><code>offline</code></td><td>Read prompt/context only; no network.</td></tr><tr><td><code>repo-read</code></td><td>Inspect source without writing changes.</td></tr><tr><td><code>repo-write</code></td><td>Create commits, branches, or generated artifacts.</td></tr><tr><td><code>deployment</code></td><td>Interact with deployment targets under strict policy.</td></tr></tbody></table><p>With the Docker provider, <code>offline</code> maps to no network. Other profiles map to Docker bridge networking unless an egress proxy or stronger provider enforces per-host rules. Use OpenSandbox or Kubernetes when host-level network policy is required.</p><h2 id="sandbox-checklist" tabindex="-1">Sandbox checklist <a class="header-anchor" href="#sandbox-checklist" aria-label="Permalink to &quot;Sandbox checklist&quot;">​</a></h2><ul><li>Enable sandboxing before running untrusted or code-writing tasks.</li><li>Match workflow <code>sandboxProfile</code> to the agent profile&#39;s allowed profiles.</li><li>Keep repository write access separate from deployment access.</li><li>Pass only the secrets the task needs.</li><li>Prefer read-only mounts unless the task must write.</li><li>Record sandbox execution evidence for later audit.</li></ul><h2 id="artifact-storage" tabindex="-1">Artifact storage <a class="header-anchor" href="#artifact-storage" aria-label="Permalink to &quot;Artifact storage&quot;">​</a></h2><p>Autofac can store artifact bytes on the local filesystem or S3-compatible storage.</p><h3 id="filesystem" tabindex="-1">Filesystem <a class="header-anchor" href="#filesystem" aria-label="Permalink to &quot;Filesystem&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Storage__Provider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">filesystem</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Storage__RootPath</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/var/lib/autofac/artifacts</span></span></code></pre></div><p>Use persistent volumes for production. Back up the artifact path if evidence retention requires it.</p><h3 id="s3" tabindex="-1">S3 <a class="header-anchor" href="#s3" aria-label="Permalink to &quot;S3&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Storage__Provider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">s3</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Storage__S3__Bucket</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">bucket</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Storage__S3__Region</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">region</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Storage__S3__AccessKeyId</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">secret</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Storage__S3__SecretAccessKey</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">secret</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Use bucket policies, encryption, lifecycle rules, and region selection that match the deployment&#39;s compliance requirements.</p><h2 id="evidence-retention" tabindex="-1">Evidence retention <a class="header-anchor" href="#evidence-retention" aria-label="Permalink to &quot;Evidence retention&quot;">​</a></h2><p>Evidence packs reference prompts, actions, decisions, approvals, artifacts, and audit entries. Decide retention policy before production:</p><ul><li>How long to keep run metadata in Postgres.</li><li>How long to keep artifact bytes.</li><li>Whether evidence packs are exported to an external records system.</li><li>Who can read evidence packs.</li><li>How incident responders retrieve evidence after a failed or disputed run.</li></ul><h2 id="storage-safety-checklist" tabindex="-1">Storage safety checklist <a class="header-anchor" href="#storage-safety-checklist" aria-label="Permalink to &quot;Storage safety checklist&quot;">​</a></h2><ul><li>Do not store artifacts on ephemeral container filesystems in production.</li><li>Encrypt storage at rest.</li><li>Restrict bucket/path access to the Autofac service identity.</li><li>Keep artifact retention aligned with audit requirements.</li><li>Verify evidence downloads after each deployment change.</li></ul>`,24)])])}const g=t(r,[["render",n]]);export{k as __pageData,g as default};
